export const NEWS_TRENDING_URL = 'https://bing-news-search1.p.rapidapi.com/news/trendingtopics?safeSearch=Off&textFormat=Raw&count=10';

export const setUrlCategory = category => `https://bing-news-search1.p.rapidapi.com/news?textFormat=Raw&safeSearch=Off&category=${category}&count=10`;

export const setUrlArticle = title => `https://newscatcher.p.rapidapi.com/v1/search?q=${title}&lang=en&sort_by=relevancy&search_in=title&page=1&media=True`;

export const setUrlSearch = text => `https://bing-news-search1.p.rapidapi.com/news/search?q=${text}&safeSearch=Off&textFormat=Raw&freshness=Day&count=1`;

export const optionsNews = {
  method: 'GET',
  headers: {
    'x-bingapis-sdk': 'true',
    'x-rapidapi-key': '322519c3f7mshb1c6ee1da1482dfp1122e4jsn696d1d6211ed',
    'x-rapidapi-host': 'bing-news-search1.p.rapidapi.com',
  },
};

export const optionsArticles = {
  method: 'GET',
  headers: {
    'x-rapidapi-key': '43f5b0b1b7msh98b68ce351846cdp1fe9bdjsn077a7897ccfa',
    'x-rapidapi-host': 'newscatcher.p.rapidapi.com',
  },
};

export const request = (url, option) => (
  fetch(url, option)
    .then((response) => {
      if (!response.ok) {
        throw Error`${response.status} - ${response.statusText}`;
      }

      return response.json();
    })
    .then(result => result)
    .catch(error => console.warn('Error: ', error))
);

export const getAllNews = async() => {
  const result = await request(NEWS_TRENDING_URL.slice(0, -9), optionsNews);

  return result.value;
};

export const getTrendingNews = async() => {
  const result = await request(NEWS_TRENDING_URL, optionsNews);

  return result;
};

getTrendingNews().then(res => console.log(
res.value));
  //res.value.map(r => r.value[0].image.url, res.value[1]));

export const getCategoryNews = async(q) => {
  const result = await request(setUrlCategory(q), optionsNews);

  return result.value;
};

export const getSearchNews = async(q) => {
  const result = await request(setUrlSearch(q), optionsNews);

  return result;
};

export const getArticlesNews = async(q) => {
  const result = await request(setUrlArticle(q), optionsArticles);

  return result.articles.filter(res => res.author !== null);
};
